@media (hover: hover) and (pointer: fine) {
  .h-scale { position: relative; overflow: hidden; }
  .h-scale > :first-child { transition: transform 1s cubic-bezier(0.19, 1, 0.22, 1), opacity 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94); transform: scaleX(1); }
  a:hover .h-scale > :first-child { transform: scale3d(1.05, 1.05, 1); }
  .h-fade { transition: opacity 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94); opacity: 0.25; }
  .h-fade ul { transition: inherit; opacity: 0; }
  .h-fade:hover, .h-fade:hover ul { opacity: 1; }
  .h-fade-invert { transition: opacity 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94); opacity: 1; }
  .h-fade-invert:hover { opacity: 0.25; }
}

